PythonJavaScript <pre><code>import requests

# 标签点击
requests.post("http://localhost:8080/api/click", json={"tag": "AB"})

# 坐标点击
requests.get("http://localhost:8080/api/click/100/200")

# 后台点击
requests.post("http://localhost:8080/api/clickAt", 
    json={"x": 100, "y": 200, "background": True})
</code></pre> <pre><code>// 标签点击
fetch("http://localhost:8080/api/click", {
  method: "POST",
  headers: {"Content-Type": "application/json"},
  body: JSON.stringify({tag: "AB"})
});

// 坐标点击
fetch("http://localhost:8080/api/click/100/200");

// 后台点击
fetch("http://localhost:8080/api/clickAt", {
  method: "POST",
  headers: {"Content-Type": "application/json"},
  body: JSON.stringify({x: 100, y: 200, background: true})
});
</code></pre>

PythonJavaScript <pre><code>import requests

base = "http://localhost:8080"

# 移动鼠标
requests.get(f"{base}/api/mouse/move/100/100")

# 输入文本
requests.post(f"{base}/api/keys", json={"keys": "Hello"})

# 发送快捷键
requests.post(f"{base}/api/hotkey", json={"keys": ["ctrl", "a"]})
</code></pre> <pre><code>const base = "http://localhost:8080";

// 移动鼠标
fetch(`${base}/api/mouse/move/100/100`);

// 输入文本
fetch(`${base}/api/keys`, {
  method: "POST",
  headers: {"Content-Type": "application/json"},
  body: JSON.stringify({keys: "Hello"})
});

// 发送快捷键
fetch(`${base}/api/hotkey`, {
  method: "POST",
  headers: {"Content-Type": "application/json"},
  body: JSON.stringify({keys: ["ctrl", "a"]})
});
</code></pre>

PythonJavaScript <pre><code>import requests

# 获取窗口列表
windows = requests.get("http://localhost:8080/api/windows").json()

# 找到记事本窗口
for win in windows:
    if "记事本" in win["title"]:
        # 激活窗口
        requests.get(f"http://localhost:8080/api/activate/{win['handle']}")
        break
</code></pre> <pre><code>// 获取窗口列表并激活记事本
fetch("http://localhost:8080/api/windows")
  .then(r =&gt; r.json())
  .then(windows =&gt; {
    const notepad = windows.find(w =&gt; w.title.includes("记事本"));
    if (notepad) {
      fetch(`http://localhost:8080/api/activate/${notepad.handle}`);
    }
  });
</code></pre>
